ucs.kql:
let lookback = 7d;
let archiveExt = dynamic([".zip",".iso",".img",".7z",".rar"]);
let pwTerms = dynamic(["password","kennwort","contraseña","パスワード","mot de passe","parola","passwort"]);
let hijackPrefix = dynamic(["re:","fwd:","aw:","tr:","r:","antw:","返信","転送"]);
let susEmails =
    EmailAttachmentInfo
    | where Timestamp > ago(lookback)
    | where FileName has_any (archiveExt)
    | where FileSize between (10000 .. 250000)  // TA551 ZIPs are small
    | join kind=inner (
        EmailEvents
        | where Timestamp > ago(lookback)
        | extend subjLower = tolower(Subject)
        | where subjLower has_any (hijackPrefix)
      ) on NetworkMessageId
    | extend bodyHasPw = iff(tolower(Subject) has_any (pwTerms), true, false)
    | project EmailTimestamp=Timestamp, NetworkMessageId, Subject, SenderFromAddress, RecipientEmailAddress, FileName, FileSize, RecipientObjectId, bodyHasPw;
let hostExec =
    DeviceProcessEvents
    | where Timestamp > ago(lookback)
    | where InitiatingProcessFileName in~ ("winword.exe","excel.exe")
    | where FileName in~ ("regsvr32.exe","mshta.exe","rundll32.exe")
    | where ProcessCommandLine has_any ("\\ProgramData\\","\\AppData\\","\\Users\\Public\\","\\Temp\\")
    | project ExecTime=Timestamp, DeviceName, AccountUpn, ProcessCommandLine, InitiatingProcessFileName, FileName;
susEmails
| join kind=inner (hostExec) on $left.RecipientEmailAddress == $right.AccountUpn
| where ExecTime between (EmailTimestamp .. EmailTimestamp + 4h)
| project EmailTimestamp, ExecTime, RecipientEmailAddress, SenderFromAddress, Subject, FileName, FileSize, DeviceName, InitiatingProcessFileName, FileName1=FileName, ProcessCommandLine
| order by EmailTimestamp desc
